#include <stdio.h> // Required for printf and scanf

int main() {
    // Declare integer variables to store the inputs
    int original_price_int;
    int discount_percentage_int;
    int shipping_threshold_int;
    int fixed_shipping_fee_int;

    // Read the four integer inputs from stdin
    // It's good practice to check the return value of scanf,
    // though the problem assumes valid input for this exercise.
    if (scanf("%d %d %d %d", &original_price_int, &discount_percentage_int, 
               &shipping_threshold_int, &fixed_shipping_fee_int) != 4) {
        // Simple error handling: exit if input fails
        return 1; 
    }

    // Convert integer inputs to double for precise floating-point calculations
    double original_price = (double)original_price_int;
    double discount_percentage = (double)discount_percentage_int;
    double shipping_threshold = (double)shipping_threshold_int;
    double fixed_shipping_fee = (double)fixed_shipping_fee_int;

    // Calculate the discount amount using arithmetic operators
    // Note: 100.0 is used to ensure floating-point division
    double discount_amount = original_price * (discount_percentage / 100.0);

    // Calculate the price after applying the discount
    double price_after_discount = original_price - discount_amount;

    // Initialize the final amount with the discounted price
    double final_amount = price_after_discount;

    // Use a conditional statement (if) to check if shipping fee needs to be added
    if (price_after_discount < shipping_threshold) {
        // Add the fixed shipping fee if the condition is met
        final_amount = final_amount + fixed_shipping_fee;
    }

    // Print the final calculated amount, formatted to two decimal places
    printf("%.2f\n", final_amount);

    return 0; // Indicate successful execution
}
